/* eslint-disable @typescript-eslint/triple-slash-reference */
/// <reference path="./.sst/platform/config.d.ts" />

function isProd(stage: string) {
  return stage === "prod" || stage === "blue" || stage === "green";
}

export default $config({
  app(input) {
    return {
      name: "checkout",
      removal: isProd(input?.stage) ? "retain" : "remove",
      protect: ["prod"].includes(input?.stage),
      home: "aws",
      providers: {
        aws: {
          region: process.env["AWS_REGION"] as aws.Region,
          defaultTags: {
            tags: {
              project: "checkout",
              technology: "nodejs",
              team: "frontend",
              iac: "sstv3",
            },
          },
        },
      },
    };
  },
  async run() {
    const appName = process.env["APP_NAME"];
    const appLabel = process.env["APP_LABEL"];
    const appGeo = process.env["GEO"];
    const useCustomDomain = !isProd($app.stage);

    const site = new sst.aws.Nextjs("site", {
      domain: useCustomDomain
        ? {
            name: `${$app.stage}.${appName}.${appGeo}.thepetlabco.info`,
            dns: sst.aws.dns(),
          }
        : undefined,
      transform: {
        cdn: {
          comment: appLabel,
        },
      },
    });

    return {
      SiteUrl: site.url,
    };
  },
});

