// This ensures S3 Block Public Access is enabled

const bucket = new sst.aws.Bucket("SiteAssets", {
  // Enable S3 Block Public Access settings
  transform: {
    bucket: {
      blockPublicAcls: true,
      blockPublicPolicy: true,
      ignorePublicAcls: true,
      restrictPublicBuckets: true,

      // Enable versioning for better data protection
      versioningConfiguration: {
        status: "Enabled",
      },

      // Enable server-side encryption
      serverSideEncryptionConfiguration: {
        rules: [{
          applyServerSideEncryptionByDefault: {
            sseAlgorithm: "AES256",
          },
        }],
      },
    },
  },
});

// If you need CloudFront to access the bucket, use OAC (Origin Access Control)
const oac = new aws.cloudfront.OriginAccessControl("BucketOAC", {
  originAccessControlOriginType: "s3",
  signingBehavior: "always",
  signingProtocol: "sigv4",
});

// Example bucket policy that only allows CloudFront access
const bucketPolicy = new aws.iam.BucketPolicy("BucketPolicy", {
  bucket: bucket.name,
